import{_ as a,o as e,c as i,a2 as l}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Skeleton 骨架屏","description":"","frontmatter":{"title":"Skeleton 骨架屏","stage":"intermediate","direction":"interaction-design","tags":["interaction-patterns","feedback","loading"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/03-feedback/skeleton.md","filePath":"03-interaction-design/notes/06-interaction-patterns/03-feedback/skeleton.md","lastUpdated":1784542968000}'),d={name:"03-interaction-design/notes/06-interaction-patterns/03-feedback/skeleton.md"};function r(n,t,s,o,h,p){return e(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="skeleton-骨架屏" tabindex="-1">Skeleton 骨架屏 <a class="header-anchor" href="#skeleton-骨架屏" aria-label="Permalink to &quot;Skeleton 骨架屏&quot;">​</a></h1><p>Skeleton 是在内容首次可用前，用接近最终结构的非交互占位保留布局。它的核心责任是表达“哪些区域正在等待”和“最终结构大致在哪里”，不是伪造数据，也不是让慢请求看起来已经完成。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>本文聚焦：</p><ul><li>根据最终内容几何设计占位结构。</li><li>用加载边界控制整页、分区和列表项的揭示。</li><li>避免占位与真实内容替换造成布局偏移。</li><li>区分首次加载、后台刷新、延迟内容、错误和真实空状态。</li><li>验证感知性能、CLS、辅助技术反馈与慢网行为。</li></ul><p>前置知识：</p><ul><li>能把界面拆成稳定外壳、数据区域和独立请求。</li><li>理解请求可能成功、失败、取消、超时或返回零数据。</li><li>能检查响应式布局、DOM 顺序和焦点。</li></ul><p>Skeleton 不负责显示可计算进度；已知完成比例属于 Progress。它也不应覆盖已经可用的旧数据，只因为后台正在刷新。</p><h2 id="skeleton-的结构契约" tabindex="-1">Skeleton 的结构契约 <a class="header-anchor" href="#skeleton-的结构契约" aria-label="Permalink to &quot;Skeleton 的结构契约&quot;">​</a></h2><p>一个骨架块需要对应最终内容中的真实区域：</p><table tabindex="0"><thead><tr><th>骨架元素</th><th>对应内容</th><th>要保留的几何</th><th>不应伪造</th></tr></thead><tbody><tr><td>媒体占位</td><td>图片、视频、图表画布</td><td>宽高比或稳定高度</td><td>具体图片含义</td></tr><tr><td>标题条</td><td>一行或两行标题</td><td>行高、最大宽度、换行上限</td><td>真实字数</td></tr><tr><td>正文条</td><td>摘要或元数据</td><td>行数范围与行距</td><td>文本内容</td></tr><tr><td>图标块</td><td>头像或对象图标</td><td>尺寸与对齐</td><td>身份、状态</td></tr><tr><td>列表行</td><td>表格或列表记录</td><td>行高、列结构</td><td>记录数量与值</td></tr><tr><td>操作区占位</td><td>加载后才知道是否存在的动作</td><td>空间边界</td><td>可点击按钮</td></tr></tbody></table><p>骨架形状不获得焦点、不接受点击，也不应使用会让辅助技术误认为真实内容的名称。</p><h2 id="加载边界决定揭示方式" tabindex="-1">加载边界决定揭示方式 <a class="header-anchor" href="#加载边界决定揭示方式" aria-label="Permalink to &quot;加载边界决定揭示方式&quot;">​</a></h2><h3 id="页面外壳" tabindex="-1">页面外壳 <a class="header-anchor" href="#页面外壳" aria-label="Permalink to &quot;页面外壳&quot;">​</a></h3><p>标题、返回入口、导航、筛选条件和已知对象身份通常可先显示。将这些稳定内容也替换成骨架，会让用户失去位置，并在路由切换时看到整页闪烁。</p><h3 id="分区边界" tabindex="-1">分区边界 <a class="header-anchor" href="#分区边界" aria-label="Permalink to &quot;分区边界&quot;">​</a></h3><p>独立请求、独立失败、独立价值的区域可以分别揭示：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S[&quot;稳定页面外壳&quot;] --&gt; A[&quot;商品结果边界&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; B[&quot;推荐边界&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; C[&quot;库存摘要边界&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; A1[&quot;结果成功&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; A2[&quot;结果为空&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; A3[&quot;结果失败&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; B1[&quot;推荐稍后揭示&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; C1[&quot;保留已知高度&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>一个次要推荐接口失败，不应阻止主要商品结果显示。反过来，过细边界会让页面持续零碎闪动；每个字段一个骨架通常破坏整体阅读。</p><h3 id="列表项边界" tabindex="-1">列表项边界 <a class="header-anchor" href="#列表项边界" aria-label="Permalink to &quot;列表项边界&quot;">​</a></h3><p>流式返回或分页加载时，可以逐组加入真实项。已显示项目保持稳定，不要因后续项目到达而重新变回占位。无限列表底部占位只表示正在取下一页，不能与“列表初次加载”混为一体。</p><h3 id="数据依赖边界" tabindex="-1">数据依赖边界 <a class="header-anchor" href="#数据依赖边界" aria-label="Permalink to &quot;数据依赖边界&quot;">​</a></h3><p>若子区域必须依赖父数据才能正确解释，例如价格需要先确定币种，则父信息未到达前不应提前显示无上下文数值。边界按语义依赖划分，而不是按接口数量机械划分。</p><h2 id="首次加载与后台刷新" tabindex="-1">首次加载与后台刷新 <a class="header-anchor" href="#首次加载与后台刷新" aria-label="Permalink to &quot;首次加载与后台刷新&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>已有可信内容</th><th>推荐表现</th></tr></thead><tbody><tr><td>首次加载</td><td>没有</td><td>在目标区域使用 Skeleton</td></tr><tr><td>路由切换到新对象</td><td>旧对象内容不适用于新对象</td><td>保留外壳，新对象数据区使用 Skeleton</td></tr><tr><td>同一对象刷新</td><td>有</td><td>保留旧内容，标明正在刷新</td></tr><tr><td>筛选变更</td><td>旧结果可能仍有参考价值</td><td>根据任务选择保留旧结果或立即保留结果区几何</td></tr><tr><td>乐观更新</td><td>已显示预期结果</td><td>标记待确认，不用骨架覆盖</td></tr><tr><td>请求失败</td><td>没有可用新内容</td><td>转为错误与恢复操作</td></tr><tr><td>成功零数据</td><td>已确认集合为空</td><td>转为 Empty State</td></tr></tbody></table><p>已经显示过的内容再次被大面积骨架替换，会破坏视觉连续性，还可能使用户刚准备点击的目标消失。React Suspense 中，已经揭示的子树若再次挂起，最近的边界可能重新显示 <code>fallback</code>；需要通过边界位置、Transition 或保留旧值策略避免不必要回退。</p><h2 id="占位几何与-cls" tabindex="-1">占位几何与 CLS <a class="header-anchor" href="#占位几何与-cls" aria-label="Permalink to &quot;占位几何与 CLS&quot;">​</a></h2><h3 id="cls-是什么" tabindex="-1">CLS 是什么 <a class="header-anchor" href="#cls-是什么" aria-label="Permalink to &quot;CLS 是什么&quot;">​</a></h3><p>Cumulative Layout Shift 衡量页面生命周期中最大的意外布局偏移突发。单次布局偏移分数由受影响视口比例与移动距离比例相乘：</p><p>[ LayoutShiftScore = ImpactFraction \\times DistanceFraction ]</p><p>CLS 是无单位分数，不是毫秒。骨架屏不保证低 CLS；若骨架高度与真实内容不同，替换时仍会推动后续内容。</p><h3 id="为媒体保留尺寸" tabindex="-1">为媒体保留尺寸 <a class="header-anchor" href="#为媒体保留尺寸" aria-label="Permalink to &quot;为媒体保留尺寸&quot;">​</a></h3><p>图片、视频和图表应在资源到达前具有可计算尺寸。优先使用：</p><ul><li>HTML 图片的固有 <code>width</code>、<code>height</code>。</li><li>CSS <code>aspect-ratio</code>。</li><li>由组件契约确定的稳定卡片媒体比例。</li><li>图表容器的响应式高度规则。</li></ul><p>如果实际媒体比例由数据决定，选择方案：</p><table tabindex="0"><thead><tr><th>方案</th><th>条件</th><th>代价</th></tr></thead><tbody><tr><td>统一裁切比例</td><td>列表视觉一致，可接受裁切</td><td>必须定义裁切焦点</td></tr><tr><td>服务端先返回尺寸元数据</td><td>原图比例必须保留</td><td>API 与缓存需携带尺寸</td></tr><tr><td>使用保守最小高度</td><td>内容高度有范围但不可提前知道</td><td>可能留下短暂空白</td></tr><tr><td>内容到达后在独立区域扩展</td><td>扩展不会推动关键操作</td><td>仍需检查偏移影响</td></tr></tbody></table><h3 id="文本高度不可精确伪造" tabindex="-1">文本高度不可精确伪造 <a class="header-anchor" href="#文本高度不可精确伪造" aria-label="Permalink to &quot;文本高度不可精确伪造&quot;">​</a></h3><p>标题长度、字体回退、本地化和用户文字缩放都会改变行数。可降低差异：</p><ul><li>与真实内容使用相同容器宽度、字体尺寸和行高。</li><li>按产品内容约束设置相同的最大行数。</li><li>让最后一条骨架线较短，但不要随机到每次布局不同。</li><li>使用真实断点规则，不按设计稿固定像素复制。</li><li>测试最长语言、200% 文本缩放与自定义字体加载。</li></ul><p>无法保证固定高度时，优先保持关键操作和已呈现内容不移动，而不是追求每个像素完全一致。</p><h3 id="列表数量不是实际数据量" tabindex="-1">列表数量不是实际数据量 <a class="header-anchor" href="#列表数量不是实际数据量" aria-label="Permalink to &quot;列表数量不是实际数据量&quot;">​</a></h3><p>骨架行数只需要填充预期可视区域并表达结构。显示 20 行骨架并不承诺会有 20 条结果。分页大小、视口高度和行高共同决定合理数量。</p><h2 id="出现时机与闪烁" tabindex="-1">出现时机与闪烁 <a class="header-anchor" href="#出现时机与闪烁" aria-label="Permalink to &quot;出现时机与闪烁&quot;">​</a></h2><p>极快请求若立即显示 Skeleton，可能产生一次无价值闪烁。可以设置短暂显示延迟，但规则必须可预测：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Waiting</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Waiting --&gt; Content: &quot;延迟阈值前完成&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Waiting --&gt; Skeleton: &quot;超过显示延迟&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Skeleton --&gt; Content: &quot;请求成功&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Skeleton --&gt; Empty: &quot;成功且零数据&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Skeleton --&gt; Error: &quot;失败或不可恢复超时&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>显示延迟只改变占位何时出现，不延迟真实内容。不要为了让动画“完整播放”强行等待数秒。若为避免一帧闪现设置最短展示时间，该时间应很短，并验证不会明显推迟可用内容。</p><p>延迟期间仍要保留目标区域尺寸，否则内容到达时发生偏移。</p><h2 id="动画与视觉" tabindex="-1">动画与视觉 <a class="header-anchor" href="#动画与视觉" aria-label="Permalink to &quot;动画与视觉&quot;">​</a></h2><p>Skeleton 可以静态显示，也可使用低强度脉冲或扫光表达仍在等待。动画不是必要条件。</p><p>动画约束：</p><ul><li>不依赖动画方向表达信息。</li><li>遵循 <code>prefers-reduced-motion</code>，减少或停止非必要运动。</li><li>大面积高对比扫光会持续吸引注意，应限制范围与频率。</li><li>不为每个小块启动独立、不同相位的动画。</li><li>页面切到后台时无需继续高频更新。</li><li>骨架与背景具有可辨识边界，但不伪装成禁用控件。</li></ul><p>不要把真实品牌图片、广告轮廓或假文字放入骨架，这会造成内容已知的错误暗示。</p><h2 id="无障碍语义" tabindex="-1">无障碍语义 <a class="header-anchor" href="#无障碍语义" aria-label="Permalink to &quot;无障碍语义&quot;">​</a></h2><h3 id="aria-busy" tabindex="-1"><code>aria-busy</code> <a class="header-anchor" href="#aria-busy" aria-label="Permalink to &quot;\`aria-busy\`&quot;">​</a></h3><p>WAI-ARIA 的 <code>aria-busy=&quot;true&quot;</code> 表示元素正在更新，辅助技术可以延后处理其内部变化；默认值为 <code>false</code>。它适合标记正在被整体替换的内容区域，但不能单独告诉用户在加载什么。</p><p>可用的组合：</p><ul><li>稳定区域标题：“商品结果”。</li><li>区域在等待时设为 busy。</li><li>一条简短、非重复的状态文本：“正在加载商品。”</li><li>完成后清除 busy，并在必要时提供“24 件商品”或“没有匹配商品”的状态。</li></ul><p>不要给每条骨架线添加 <code>aria-label=&quot;加载中&quot;</code>，否则屏幕阅读器会听到大量重复项。装饰骨架应从可访问树中隐藏。</p><h3 id="焦点" tabindex="-1">焦点 <a class="header-anchor" href="#焦点" aria-label="Permalink to &quot;焦点&quot;">​</a></h3><ul><li>骨架内部没有可聚焦元素。</li><li>用户触发局部刷新后，焦点通常留在触发控件或当前任务位置。</li><li>路由进入新页面时，焦点管理由页面导航负责，不由骨架随意抢夺。</li><li>内容替换后不能把焦点元素删除；若必须替换，先定义合理的新焦点目标。</li><li>已可用的导航和取消操作不能因数据区 busy 而不可访问。</li></ul><h3 id="状态消息频率" tabindex="-1">状态消息频率 <a class="header-anchor" href="#状态消息频率" aria-label="Permalink to &quot;状态消息频率&quot;">​</a></h3><p>首次显示、显著等待和最终结果需要反馈；每个子请求完成都播报会形成噪声。将同一边界内的多个 DOM 更新合并，在最终可用时清除 busy。</p><h2 id="skeleton、spinner-与保留旧内容" tabindex="-1">Skeleton、Spinner 与保留旧内容 <a class="header-anchor" href="#skeleton、spinner-与保留旧内容" aria-label="Permalink to &quot;Skeleton、Spinner 与保留旧内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>适用条件</th><th>优点</th><th>风险</th></tr></thead><tbody><tr><td>Skeleton</td><td>首次加载且最终结构可预测</td><td>保留几何与内容结构</td><td>错误尺寸制造偏移</td></tr><tr><td>Spinner</td><td>小区域、结构未知或短暂动作</td><td>实现简单，不伪造结构</td><td>无法表达占用空间</td></tr><tr><td>保留旧内容</td><td>同一对象后台刷新</td><td>连续可读、减少闪动</td><td>必须标出数据新鲜度</td></tr><tr><td>空白保留区</td><td>内容次要且尺寸已知</td><td>视觉安静</td><td>用户可能不知仍在加载</td></tr><tr><td>渐进揭示</td><td>区域相互独立</td><td>主要内容更早可用</td><td>过细会持续跳动</td></tr></tbody></table><p>不要因“Skeleton 看起来更现代”选择它。若最终内容结构完全未知，例如服务器可能返回文档、视频或复杂审批表，通用骨架会给出错误预期。</p><h2 id="工程状态模型" tabindex="-1">工程状态模型 <a class="header-anchor" href="#工程状态模型" aria-label="Permalink to &quot;工程状态模型&quot;">​</a></h2><p>一个数据区域至少区分：</p><table tabindex="0"><thead><tr><th>状态</th><th>数据</th><th>请求</th><th>界面</th></tr></thead><tbody><tr><td><code>idle</code></td><td>无</td><td>未开始</td><td>不显示加载占位</td></tr><tr><td><code>delaying</code></td><td>无</td><td>进行中</td><td>保留空间，尚未显示 Skeleton</td></tr><tr><td><code>initial-loading</code></td><td>无</td><td>进行中</td><td>Skeleton 与加载状态</td></tr><tr><td><code>ready</code></td><td>有</td><td>无</td><td>真实内容</td></tr><tr><td><code>refreshing</code></td><td>有</td><td>进行中</td><td>旧内容与刷新标识</td></tr><tr><td><code>empty</code></td><td>已确认空</td><td>无</td><td>对应原因的空状态</td></tr><tr><td><code>error</code></td><td>无或旧数据</td><td>失败</td><td>错误、重试或旧数据</td></tr><tr><td><code>cancelled</code></td><td>无或旧数据</td><td>已取消</td><td>恢复到稳定状态</td></tr></tbody></table><p>请求身份要与对象、筛选和版本绑定。用户快速切换筛选时，旧请求晚到不能覆盖新结果。Skeleton 只能反映当前有效请求，不能由任意 pending 布尔值控制。</p><h2 id="案例一-商品搜索结果网格" tabindex="-1">案例一：商品搜索结果网格 <a class="header-anchor" href="#案例一-商品搜索结果网格" aria-label="Permalink to &quot;案例一：商品搜索结果网格&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>搜索页在 1440 CSS px 下每行 4 张卡片，在 390 CSS px 下每行 2 张。商品图统一裁切为 4:3；标题最多两行；价格一行；促销标签可能不存在。搜索接口和推荐接口独立。</p><p>目标是：</p><ul><li>首次搜索时保留结果区结构。</li><li>筛选切换时不让页面工具栏和分页跳动。</li><li>零结果、接口错误与仍在加载可区分。</li></ul><h3 id="边界设计" tabindex="-1">边界设计 <a class="header-anchor" href="#边界设计" aria-label="Permalink to &quot;边界设计&quot;">​</a></h3><p>页面标题、查询词、筛选控件和排序保持真实。只有结果集合进入加载边界。推荐区在主要结果之后独立加载，不阻塞结果。</p><p>骨架卡片按真实断点使用相同网格：</p><ul><li>媒体区固定 4:3。</li><li>标题区保留两行最大高度。</li><li>价格区保留一行。</li><li>促销标签不预留固定位置，因为真实布局把它叠加在媒体区，不会推动正文。</li></ul><p>第一页骨架数量覆盖首个视口和一部分滚动区域；它不显示虚假商品数量。</p><h3 id="状态转换" tabindex="-1">状态转换 <a class="header-anchor" href="#状态转换" aria-label="Permalink to &quot;状态转换&quot;">​</a></h3><p>首次请求超过短延迟才显示骨架。用户改变筛选时，旧结果可保留但降低“当前筛选已应用”的暗示，并显示结果区正在更新；新结果到达后原位替换。</p><p>若筛选导致零结果，转为空状态并保留筛选栏。若请求失败，保留旧结果并标记它们对应上一次成功条件，同时提供重试；没有旧结果时显示区域级错误。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>在 Chrome DevTools 以慢速网络记录布局偏移。</li><li>检查骨架和真实卡片的媒体比例、行高与网格断点。</li><li>快速连续修改品牌、价格和排序，确认过期响应不会覆盖最新条件。</li><li>断网时区分旧数据与失败请求。</li><li>用键盘修改筛选，焦点不进入骨架，也不在结果替换时丢失。</li><li>屏幕阅读器只听到一次加载状态和一次最终结果数量。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若商品标题本地化后从两行增长到三行，而真实卡片未限制行数，后续每一行网格都会被推移。修复应统一真实内容约束或采用能容纳三行的稳定布局，不是只把骨架做高来掩盖卡片规则不一致。</p><h2 id="案例二-财务看板的分区加载" tabindex="-1">案例二：财务看板的分区加载 <a class="header-anchor" href="#案例二-财务看板的分区加载" aria-label="Permalink to &quot;案例二：财务看板的分区加载&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>看板包含账户余额、现金流图、应收账款表和汇率更新时间。四个区域来自不同服务；余额是关键数据，汇率说明决定金额是否可比较。用户常在后台刷新时继续查看上次结果。</p><h3 id="边界设计-1" tabindex="-1">边界设计 <a class="header-anchor" href="#边界设计-1" aria-label="Permalink to &quot;边界设计&quot;">​</a></h3><p>首次进入：</p><ul><li>页面标题、期间选择和币种显示真实。</li><li>余额摘要与汇率说明作为同一语义边界，避免先显示无汇率上下文的总额。</li><li>现金流图保留固定画布高度。</li><li>应收表按真实表头和行高保留结构，但表头文字保持可见。</li></ul><p>后台刷新：</p><ul><li>保留上次数据和“数据时间”。</li><li>各区域显示非阻塞刷新状态。</li><li>新数据只有在同一快照版本完整时一起提交，避免余额与汇率来自不同时间。</li></ul><h3 id="快照与显示规则" tabindex="-1">快照与显示规则 <a class="header-anchor" href="#快照与显示规则" aria-label="Permalink to &quot;快照与显示规则&quot;">​</a></h3><p>每个区域返回 <code>snapshot_id</code>、<code>as_of</code> 和状态。页面只把具有兼容快照的余额与汇率组合。现金流可以独立更新，但标题明确期间与数据时间。</p><p>首次加载失败时不显示虚假零值；旧快照存在时继续显示，并标明刷新失败。Skeleton 只用于没有任何可用快照的区域。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>分别延迟余额、汇率、图表和表格请求，检查边界是否符合语义依赖。</li><li>让汇率失败，确认余额不会被错误解释为最新换算值。</li><li>记录图表骨架替换后的 CLS 与滚动位置。</li><li>切换期间后立即切回，确认请求取消与快照身份。</li><li>检查旧数据状态在屏幕阅读器中包含数据时间，不只靠降低透明度。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若所有分区共享一个全页 Skeleton，次要图表超时会遮住已到达的余额；若每个数值独立揭示，又会形成不同快照拼接。正确边界由数据一致性决定：余额与汇率成组，图表和表格可独立。</p><h2 id="调试与观测" tabindex="-1">调试与观测 <a class="header-anchor" href="#调试与观测" aria-label="Permalink to &quot;调试与观测&quot;">​</a></h2><h3 id="调试顺序" tabindex="-1">调试顺序 <a class="header-anchor" href="#调试顺序" aria-label="Permalink to &quot;调试顺序&quot;">​</a></h3><ol><li>固定视口、网络、缓存、字体和数据内容。</li><li>记录哪个边界进入加载以及触发请求的身份。</li><li>比较骨架和真实内容的盒模型、网格轨道、行高与媒体比例。</li><li>在 Performance 面板查看 Layout Shift 记录和受影响元素。</li><li>检查请求竞争、取消和旧响应覆盖。</li><li>检查 busy 状态何时设置与清除。</li><li>在错误、零数据和后台刷新条件下重复。</li></ol><h3 id="观测信号" tabindex="-1">观测信号 <a class="header-anchor" href="#观测信号" aria-label="Permalink to &quot;观测信号&quot;">​</a></h3><ul><li>Skeleton 实际可见时长分布，而不是请求总时长。</li><li>首次加载与后台刷新分别统计。</li><li>从 Skeleton 到内容、空状态和错误的转换比例。</li><li>页面与关键区域的 CLS，按移动和桌面第 75 百分位观察。</li><li>请求完成到真实内容可交互的延迟。</li><li>骨架期间的重复点击、返回或离开。</li></ul><p>骨架可见时长下降不一定表示性能改善，可能只是显示延迟变长。必须同时看真实内容可用时间。</p><h2 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h2><ol><li>让接口在显示延迟前后交替完成，检查闪烁。</li><li>让图片尺寸元数据缺失。</li><li>使用 40 字标题和 200% 文本缩放。</li><li>让旧请求在新筛选后晚到。</li><li>让一个分区成功、一个失败、一个持续等待。</li><li>在 Skeleton 显示时浏览器后退再前进。</li><li>开启减少动态效果偏好。</li><li>让字体在内容替换后才加载。</li></ol><p>每次检查布局、焦点、辅助技术状态、请求身份和最终数据是否一致。</p><h2 id="综合练习-设计可验证的加载边界" tabindex="-1">综合练习：设计可验证的加载边界 <a class="header-anchor" href="#综合练习-设计可验证的加载边界" aria-label="Permalink to &quot;综合练习：设计可验证的加载边界&quot;">​</a></h2><p>为一个含列表、媒体和三个独立摘要区的页面交付：</p><ol><li>稳定外壳与加载边界图。</li><li>每个骨架块到真实内容的几何映射。</li><li>首次加载、刷新、零数据、错误和取消状态表。</li><li>慢网、长文本、字体延迟与旧响应的失败注入结果。</li><li>CLS、骨架可见时长和内容可用时间观测方案。</li><li>键盘、屏幕阅读器和减少动态效果验收。</li></ol><p>验收标准：</p><ul><li>每个占位都对应真实结构，不伪造可点击控件。</li><li>首次加载与后台刷新采用不同反馈。</li><li>骨架替换不会让关键操作发生意外位移。</li><li>空、错误和权限状态不会永久停留在 Skeleton。</li><li>过期响应不能覆盖当前对象或筛选。</li><li>装饰骨架不进入可访问树，区域 busy 状态能正确结束。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://web.dev/articles/cls" target="_blank" rel="noreferrer">web.dev：Cumulative Layout Shift (CLS)</a>（访问日期：2026-07-18）</li><li><a href="https://web.dev/articles/optimize-cls" target="_blank" rel="noreferrer">web.dev：Optimize Cumulative Layout Shift</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/wai-aria-1.2/#aria-busy" target="_blank" rel="noreferrer">W3C：Accessible Rich Internet Applications 1.2 — <code>aria-busy</code></a>（访问日期：2026-07-18）</li><li><a href="https://react.dev/reference/react/Suspense" target="_blank" rel="noreferrer">React：<code>&lt;Suspense&gt;</code></a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/css-sizing-4/" target="_blank" rel="noreferrer">W3C：CSS Box Sizing Module Level 4</a>（访问日期：2026-07-18）</li></ul>`,117)])])}const b=a(d,[["render",r]]);export{u as __pageData,b as default};
